function describe(value: unknown): string {
  if (typeof value === "string") {
    return `string: "${value}"`;
  }
  if (typeof value === "number") {
    return `number: ${value}`;
  }
  return "unknown type";
}

console.log(describe("hello"));
console.log(describe(42));
console.log(describe(true));
